(()=>{document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".post").forEach(s=>{let e=s.querySelector(".collapsible"),t=s.querySelector(".post-abstract");e.addEventListener("click",function(){t.style.display==="block"||t.style.display===""?(t.style.display="none",e.textContent="show abstract \u25BC"):(t.style.display="block",e.textContent="hide abstract \u25B2")})})});})();
